// Normalize health-check response to a consistent shape so callers don't have
// to handle three cases (2xx ok, non-2xx body, transport error).
const input = $input.first();
const json = input?.json ?? {};
const err  = json.error || json.errorMessage;

if (err) {
  return [{ json: { healthy: false, status: 'unreachable', error: String(err).slice(0, 300) } }];
}

// Relay /health returns { status: 'ok', ... } on healthy; anything else is a soft fail.
const healthy = json.status === 'ok';
return [{ json: {
  healthy,
  status: json.status || 'unknown',
  port: json.port ?? null,
  sessions: json.sessions ?? null,
  discord: json.discord ?? null,
  error: healthy ? null : 'relay reported non-ok status'
}}];
